const ADD_POST = "ADDPOST";
const NEW_POST = "NEWPOST";
let initialState = {
  messegData: [],
  newChanges: "",
};
const messegDataReducer = (state = initialState, action) => {
  switch (action.type) {
    case NEW_POST: {
      return { ...state, newChanges: action.newChange };
    }
    case ADD_POST:
      if (state.newChanges === "") {
        return state;
      }
      return {
        ...state,
        messegData: [...state.messege, { messege: state.newChanges }],
      };
    default:
      return state;
  }
};

export const addPostcreateActin = () => ({ type: ADD_POST });

export const onPostChangecreateActin = (text) => ({
  type: NEW_POST,
  newChange: text,
});
export default messegDataReducer;
